  1→package search
  2→
  3→import (
  4→	"fmt"
  5→	"strings"
  6→)
  7→
  8→// BuildQuery builds a parameterised SELECT query against search_base.dataset_merged.
  9→// It selects the core result columns plus computed distance and myPrice columns,
 10→// applies WHERE clauses for the request's filters, and appends ORDER BY / LIMIT / OFFSET.
 11→func BuildQuery(reg *Registry, req SearchRequest) (sql string, args []any, err error) {
 12→	clauses, args, err := buildWhere(reg, req.Filters)
 13→	if err != nil {
 14→		return "", nil, err
 15→	}
 16→
 17→	argStart := len(args) + 1
 18→
 19→	// Always select 10 columns so Scan is uniform.
 20→	distanceExpr := "NULL::double precision"
 21→	myPriceExpr := "NULL::integer"
 22→	blendExpr := "NULL::double precision"
 23→
 24→	if req.UserLocation != nil {
 25→		// Distance in miles via PostGIS geography.
 26→		distanceExpr = fmt.Sprintf(
 27→			"ST_Distance(coordinates, ST_SetSRID(ST_MakePoint($%d, $%d), 4326)::geography) / 1609.344",
 28→			argStart, argStart+1,
 29→		)
 30→		args = append(args, req.UserLocation.Longitude, req.UserLocation.Latitude)
 31→		argStart += 2
 32→
 33→		if req.UserLocation.State != "" {
 34→			myPriceExpr = fmt.Sprintf(
 35→				"CASE WHEN state = $%d THEN (data #>> '{nces,tuition_in_state}')::integer "+
 36→					"ELSE (data #>> '{nces,tuition_out_of_state}')::integer END",
 37→				argStart,
 38→			)
 39→			args = append(args, req.UserLocation.State)
 40→			argStart++
 41→		}
 42→	}
 43→
 44→	if req.Blend != nil {
 45→		expr, berr := buildBlendExpression(reg, req.Blend)
 46→		if berr != nil {
 47→			return "", nil, berr
 48→		}
 49→		blendExpr = expr
 50→	}
 51→
 52→	q := fmt.Sprintf(
 53→		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
 54→		distanceExpr, myPriceExpr, blendExpr,
 55→	)
 56→	if len(clauses) > 0 {
 57→		q += " WHERE " + strings.Join(clauses, " AND ")
 58→	}
 59→
 60→	// ORDER BY: blend overrides user sort when active.
 61→	if req.Blend != nil {
 62→		q += " ORDER BY 10 ASC NULLS LAST"
 63→	} else {
 64→		orderBy, err := buildOrderBy(reg, req)
 65→		if err != nil {
 66→			return "", nil, err
 67→		}
 68→		q += orderBy
 69→	}
 70→
 71→	limit := req.Limit
 72→	if limit <= 0 {
 73→		limit = DefaultLimit
 74→	}
 75→	if limit > MaxLimit {
 76→		limit = MaxLimit
 77→	}
 78→	offset := req.Offset
 79→	if offset < 0 {
 80→		offset = 0
 81→	}
 82→	if offset+limit > MaxLimit {
 83→		offset = MaxLimit - limit
 84→		if offset < 0 {
 85→			offset = 0
 86→		}
 87→	}
 88→	q += fmt.Sprintf(" LIMIT $%d OFFSET $%d", argStart, argStart+1)
 89→	args = append(args, limit, offset)
 90→
 91→	return q, args, nil
 92→}
 93→
 94→// buildOrderBy returns an ORDER BY clause based on the sort input.
 95→// It handles the built-in DISTANCE and NAME sorts as special cases, and looks
 96→// up any other field name in the registry to generate a column or JSONB sort.
 97→func buildOrderBy(reg *Registry, req SearchRequest) (string, error) {
 98→	if req.Sort == nil {
 99→		return " ORDER BY institution_name ASC", nil
100→	}
101→
102→	dir := "ASC"
103→	if req.Sort.Direction == SortDirectionDesc {
104→		dir = "DESC"
105→	}
106→
107→	nulls := "NULLS LAST"
108→	if dir == "DESC" {
109→		nulls = "NULLS FIRST"
110→	}
111→
112→	switch req.Sort.Field {
113→	case "distance":
114→		// Column 7 is the distance expression.
115→		return fmt.Sprintf(" ORDER BY 7 %s %s", dir, nulls), nil
116→	case "name":
117→		return fmt.Sprintf(" ORDER BY institution_name %s", dir), nil
118→	}
119→
120→	// Look up field in registry.
121→	field, ok := reg.Lookup(req.Sort.Field)
122→	if !ok {
123→		return "", fmt.Errorf("search: unknown sort field %q", req.Sort.Field)
124→	}
125→	if !field.Descriptor().Sortable {
126→		return "", fmt.Errorf("search: field %q is not sortable", req.Sort.Field)
127→	}
128→
129→	src := field.Source()
130→	switch src.Kind {
131→	case SourceColumn:
132→		return fmt.Sprintf(" ORDER BY %s %s %s", src.Column, dir, nulls), nil
133→	case SourceJSONBPath:
134→		castType := sqlCastType(src.ValueType)
135→		return fmt.Sprintf(" ORDER BY (%s)::%s %s %s", src.SQLRef(), castType, dir, nulls), nil
136→	default:
137→		return "", fmt.Errorf("search: field %q has unsortable source kind %q", req.Sort.Field, src.Kind)
138→	}
139→}
