 96→const MILES_TO_KM = 1.60934
 97→
 98→export function buildFilterInputs(
 99→  filters: Record<string, unknown>,
100→): Array<{ field: string; value: unknown }> {
101→  return Object.entries(filters).map(([field, value]) => {
102→    if (
103→      typeof value === 'object' &&
104→      value !== null &&
105→      'latitude' in value &&
106→      'longitude' in value &&
107→      'radiusMiles' in value
108→    ) {
109→      const v = value as { latitude: number; longitude: number; radiusMiles: number }
110→      return {
111→        field,
112→        value: {
113→          kind: 'radius',
114→          radius: { lat: v.latitude, lng: v.longitude, radius_km: v.radiusMiles * MILES_TO_KM },
115→        },
116→      }
117→    }
118→    return { field, value }
119→  })
120→}
