239→ * Navigates a dot-path (e.g. "academics.enrollment") into a SearchInstitution
240→ * and returns the leaf value. Returns undefined if any segment is missing.
241→ */
242→export function getFieldValue(
243→  inst: SearchInstitution,
244→  outputKey: string | null | undefined,
245→): unknown {
246→  if (!outputKey) return undefined
247→  const parts = outputKey.split('.')
248→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
249→  let current: any = inst
250→  for (const part of parts) {
251→    if (current == null || typeof current !== 'object') return undefined
252→    current = current[part]
253→  }
254→  return current ?? undefined
