const handleSort = useCallback(
  (field: string) => {
    setSearchParams(
      (prev) => {
        const next = new URLSearchParams(prev)
        const currentField = next.get('sort')
        const currentDir = next.get('sortDir') ?? 'ASC'

        if (currentField === field) {
          if (currentDir === 'ASC') {
            // ASC → DESC
            next.set('sortDir', 'DESC')
          } else {
            // DESC → clear
            next.delete('sort')
            next.delete('sortDir')
          }
        } else {
          // New field → ASC
          next.set('sort', field)
          next.delete('sortDir')
        }
        next.delete('page')
        return next
      },
      { replace: true },
    )
  },
  [setSearchParams],
)

const handleBlendChange = useCallback(
  (weights: Record<string, number>) => {
    setSearchParams(
      (prev) => {
        const next = new URLSearchParams(prev)
        const serialized = serializeBlendWeights(weights)
        if (serialized) {
          next.set('blend', serialized)
          // Clear sort when blend is active — blend determines ordering
          next.delete('sort')
          next.delete('sortDir')
        } else {
          next.delete('blend')
        }
        next.delete('page')
        return next
      },

