 94→// buildOrderBy returns an ORDER BY clause based on the sort input.
 95→// It handles the built-in DISTANCE and NAME sorts as special cases, and looks
 96→// up any other field name in the registry to generate a column or JSONB sort.
 97→func buildOrderBy(reg *Registry, req SearchRequest) (string, error) {
 98→	if req.Sort == nil {
 99→		return " ORDER BY institution_name ASC", nil
100→	}
101→
102→	dir := "ASC"
103→	if req.Sort.Direction == SortDirectionDesc {
104→		dir = "DESC"
105→	}
106→
107→	nulls := "NULLS LAST"
108→	if dir == "DESC" {
109→		nulls = "NULLS FIRST"
110→	}
111→
112→	switch req.Sort.Field {
113→	case "distance":
114→		// Column 7 is the distance expression.
115→		return fmt.Sprintf(" ORDER BY 7 %s %s", dir, nulls), nil
116→	case "name":
117→		return fmt.Sprintf(" ORDER BY institution_name %s", dir), nil
118→	}
119→
120→	// Look up field in registry.
121→	field, ok := reg.Lookup(req.Sort.Field)
122→	if !ok {
123→		return "", fmt.Errorf("search: unknown sort field %q", req.Sort.Field)
124→	}
125→	if !field.Descriptor().Sortable {
126→		return "", fmt.Errorf("search: field %q is not sortable", req.Sort.Field)
127→	}
128→
129→	src := field.Source()
130→	switch src.Kind {
131→	case SourceColumn:
132→		return fmt.Sprintf(" ORDER BY %s %s %s", src.Column, dir, nulls), nil
133→	case SourceJSONBPath:
134→		castType := sqlCastType(src.ValueType)
