import { Box, Group, Stack, Text } from '@mantine/core'
import { MapPin, DollarSign } from 'lucide-react'
import type { SearchInstitution } from './types'

function formatDistance(d: number): string {
  if (d < 1) return '< 1 mi'
  return `${Math.round(d)} mi`
}

function formatPrice(p: number): string {
  return `$${p.toLocaleString()}`
}

interface ResultsListProps {
  institutions: SearchInstitution[]
  hasLocation: boolean
  hasState: boolean
  onClickInstitution: (unitID: string) => void
}

export function ResultsList({
  institutions,
  hasLocation,
  hasState,
  onClickInstitution,
}: ResultsListProps) {
  return (
    <Stack gap={0}>
      {institutions.map((inst) => (
        <Box
          key={inst.unitID}
          role="button"
          tabIndex={0}
          onClick={() => onClickInstitution(inst.unitID)}
          onKeyDown={(e) => {
            if (e.key === 'Enter' || e.key === ' ') {
              e.preventDefault()
              onClickInstitution(inst.unitID)
            }
          }}
          style={{
            cursor: 'pointer',
            padding: '8px 12px',
            borderBottom: '1px solid var(--mantine-color-gray-2)',
          }}
        >
          <Group justify="space-between" wrap="nowrap" gap="sm">
            <Group gap="xs" wrap="nowrap" style={{ minWidth: 0 }}>
              <Text fw={600} c="brand.9" truncate="end" style={{ minWidth: 0 }}>
                {inst.name}
              </Text>
              <Text fz="sm" c="dimmed" style={{ whiteSpace: 'nowrap' }}>
                {inst.city}, {inst.state}
              </Text>
            </Group>
            {(hasLocation || hasState) && (
              <Group gap="sm" wrap="nowrap" style={{ flexShrink: 0 }}>
                {hasLocation && inst.distance != null && (
                  <Text
                    fz="sm"
                    c="dimmed"
                    data-testid="distance"
                    style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
                  >
                    <MapPin size={14} />
                    {formatDistance(inst.distance)}
                  </Text>
                )}
                {hasState && inst.myPrice != null && (
                  <Text
                    fz="sm"
                    c="dimmed"
                    data-testid="my-price"
                    style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}
                  >
                    <DollarSign size={14} />
                    {formatPrice(inst.myPrice)}
                  </Text>
                )}
              </Group>
            )}
          </Group>
        </Box>
      ))}
    </Stack>
  )
}

