// ─────────────────────────────────────────────────────────────────────────────

func TestBuildQuery_WithSort(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("sort by name ASC", func(t *testing.T) {
		req := search.SearchRequest{
			Limit: 10,
			Sort:  &search.SortInput{Field: "name", Direction: search.SortDirectionAsc},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY institution_name ASC") {
			t.Errorf("expected ORDER BY institution_name ASC: %s", sql)
		}
	})

	t.Run("sort by name DESC", func(t *testing.T) {
		req := search.SearchRequest{
			Limit: 10,
			Sort:  &search.SortInput{Field: "name", Direction: search.SortDirectionDesc},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY institution_name DESC") {
			t.Errorf("expected ORDER BY institution_name DESC: %s", sql)
		}
	})

	t.Run("sort by distance", func(t *testing.T) {
		req := search.SearchRequest{
			Limit:        10,
			UserLocation: &search.UserLocation{Latitude: 40.0, Longitude: -74.0},
			Sort:         &search.SortInput{Field: "distance"},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY 7 ASC NULLS LAST") {
			t.Errorf("expected ORDER BY 7 ASC NULLS LAST: %s", sql)
		}
	})

	t.Run("sort by distance DESC", func(t *testing.T) {
		req := search.SearchRequest{
			Limit:        10,
			UserLocation: &search.UserLocation{Latitude: 40.0, Longitude: -74.0},
			Sort:         &search.SortInput{Field: "distance", Direction: search.SortDirectionDesc},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY 7 DESC NULLS FIRST") {
			t.Errorf("expected ORDER BY 7 DESC NULLS FIRST: %s", sql)
		}
	})

	t.Run("default sort is name ASC", func(t *testing.T) {
		req := search.SearchRequest{Limit: 10}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY institution_name ASC") {
			t.Errorf("expected default ORDER BY institution_name ASC: %s", sql)
		}
	})

	t.Run("sort by JSONB field enrollment ASC", func(t *testing.T) {
		req := search.SearchRequest{
			Limit: 10,
			Sort:  &search.SortInput{Field: "enrollment", Direction: search.SortDirectionAsc},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY (data #>> '{nces,size}')::integer ASC NULLS LAST") {
			t.Errorf("unexpected ORDER BY clause: %s", sql)
		}
	})

	t.Run("sort by JSONB field admission_rate DESC", func(t *testing.T) {
		req := search.SearchRequest{
			Limit: 10,
			Sort:  &search.SortInput{Field: "admission_rate", Direction: search.SortDirectionDesc},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY (data #>> '{nces,admission_rate_overall}')::numeric DESC NULLS FIRST") {
			t.Errorf("unexpected ORDER BY clause: %s", sql)
		}
	})

	t.Run("sort by column field city ASC", func(t *testing.T) {
		req := search.SearchRequest{
			Limit: 10,
			Sort:  &search.SortInput{Field: "city", Direction: search.SortDirectionAsc},
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ORDER BY city ASC NULLS LAST") {
			t.Errorf("unexpected ORDER BY clause: %s", sql)
		}
	})

	t.Run("sort by unknown field returns error", func(t *testing.T) {
		req := search.SearchRequest{
			Limit: 10,
			Sort:  &search.SortInput{Field: "nonexistent"},
		}
		_, _, err := search.BuildQuery(reg, req)
		if err == nil {
			t.Fatal("expected error for unknown sort field")
		}
		if !strings.Contains(err.Error(), "unknown sort field") {
			t.Errorf("unexpected error: %v", err)
		}
	})

)

// User location from URL params
const userLocation = useMemo(() => {
  const lat = searchParams.get('userLat')
  const lng = searchParams.get('userLng')
  if (lat == null || lng == null) return undefined
  const latitude = Number(lat)
  const longitude = Number(lng)
  if (Number.isNaN(latitude) || Number.isNaN(longitude)) return undefined
  const state = searchParams.get('userState') ?? undefined
  return { latitude, longitude, state }
}, [searchParams])

// Sort state from URL params
const sort = useMemo((): SortState | undefined => {
  const sortParam = searchParams.get('sort')
  if (!sortParam) return undefined
  const dirParam = searchParams.get('sortDir')
  const direction = dirParam === 'DESC' ? ('DESC' as const) : ('ASC' as const)
  return { field: sortParam, direction }
}, [searchParams])

// Ranking blend weights from URL params
const blendWeights = useMemo(
  () => parseBlendParam(searchParams.get('blend')),
  [searchParams],
)
const hasBlend = Object.keys(blendWeights).length > 0

// Pagination state from URL params
const pageSize = useMemo(() => {
  const ps = Number(searchParams.get('pageSize'))
  return PAGE_SIZE_OPTIONS.includes(ps) ? ps : DEFAULT_PAGE_SIZE
}, [searchParams])

const page = useMemo(() => {
  const p = Number(searchParams.get('page'))
  return p >= 1 ? p : 1
}, [searchParams])

const offset = (page - 1) * pageSize

const [searchResult] = useQuery<{
  search: { results: SearchInstitution[]; total: number; limit: number; offset: number }
}>({
  query: SearchQuery,
  variables: {
    filters: buildFilterInputs(filters),
    limit: pageSize,
    offset,
    sort: hasBlend ? null : (sort ?? null),
    userLocation: userLocation
      ? {
          latitude: userLocation.latitude,
          longitude: userLocation.longitude,
          state: userLocation.state,
        }
      : null,
    rankingBlend: hasBlend
      ? Object.entries(blendWeights).map(([field, weight]) => ({ field, weight }))
      : null,
  },
  pause: fieldsResult.fetching,
})

const themeGroups = useMemo(
  () => fieldsByTheme(fields.filter((f) => f.visibility !== 'HIDDEN')),
  [fields],
)

