package search

import (
	"fmt"
	"strings"
)

// BuildQuery builds a parameterised SELECT query against search_base.dataset_merged.
// It selects the core result columns plus computed distance and myPrice columns,
// applies WHERE clauses for the request's filters, and appends ORDER BY / LIMIT / OFFSET.
func BuildQuery(reg *Registry, req SearchRequest) (sql string, args []any, err error) {
	clauses, args, err := buildWhere(reg, req.Filters)
	if err != nil {
		return "", nil, err
	}

	argStart := len(args) + 1

	// Always select 10 columns so Scan is uniform.
	distanceExpr := "NULL::double precision"
	myPriceExpr := "NULL::integer"
	blendExpr := "NULL::double precision"

	if req.UserLocation != nil {
		// Distance in miles via PostGIS geography.
		distanceExpr = fmt.Sprintf(
			"ST_Distance(coordinates, ST_SetSRID(ST_MakePoint($%d, $%d), 4326)::geography) / 1609.344",
			argStart, argStart+1,
		)
		args = append(args, req.UserLocation.Longitude, req.UserLocation.Latitude)
		argStart += 2

		if req.UserLocation.State != "" {
			myPriceExpr = fmt.Sprintf(
				"CASE WHEN state = $%d THEN (data #>> '{nces,tuition_in_state}')::integer "+
					"ELSE (data #>> '{nces,tuition_out_of_state}')::integer END",
				argStart,
			)
			args = append(args, req.UserLocation.State)
			argStart++
		}
	}

	if req.Blend != nil {
		expr, berr := buildBlendExpression(reg, req.Blend)
		if berr != nil {
			return "", nil, berr
		}
		blendExpr = expr
	}

	q := fmt.Sprintf(
		"SELECT unit_id, institution_name, city, state, latitude, longitude, %s, %s, data, %s AS blend_score FROM search_base.dataset_merged",
		distanceExpr, myPriceExpr, blendExpr,
	)
	if len(clauses) > 0 {
		q += " WHERE " + strings.Join(clauses, " AND ")
	}

	// ORDER BY: blend overrides user sort when active.
	if req.Blend != nil {
		q += " ORDER BY 10 ASC NULLS LAST"
	} else {
		orderBy, err := buildOrderBy(reg, req)
		if err != nil {
			return "", nil, err
		}
		q += orderBy
	}

	limit := req.Limit
	if limit <= 0 {
		limit = DefaultLimit
	}
	if limit > MaxLimit {
		limit = MaxLimit
	}
	offset := req.Offset
	if offset < 0 {
		offset = 0
	}
	if offset+limit > MaxLimit {
		offset = MaxLimit - limit
		if offset < 0 {
			offset = 0
		}
	}
	q += fmt.Sprintf(" LIMIT $%d OFFSET $%d", argStart, argStart+1)
	args = append(args, limit, offset)

	return q, args, nil
}

// buildOrderBy returns an ORDER BY clause based on the sort input.
// It handles the built-in DISTANCE and NAME sorts as special cases, and looks
// up any other field name in the registry to generate a column or JSONB sort.
func buildOrderBy(reg *Registry, req SearchRequest) (string, error) {
	if req.Sort == nil {
		return " ORDER BY institution_name ASC", nil
	}

	dir := "ASC"
	if req.Sort.Direction == SortDirectionDesc {
		dir = "DESC"
	}

	nulls := "NULLS LAST"
	if dir == "DESC" {
		nulls = "NULLS FIRST"
	}

	switch req.Sort.Field {
	case "distance":
		// Column 7 is the distance expression.
		return fmt.Sprintf(" ORDER BY 7 %s %s", dir, nulls), nil
	case "name":
		return fmt.Sprintf(" ORDER BY institution_name %s", dir), nil
	}

	// Look up field in registry.
	field, ok := reg.Lookup(req.Sort.Field)
	if !ok {
		return "", fmt.Errorf("search: unknown sort field %q", req.Sort.Field)
	}
	if !field.Descriptor().Sortable {
		return "", fmt.Errorf("search: field %q is not sortable", req.Sort.Field)
	}

	src := field.Source()
	switch src.Kind {
	case SourceColumn:
		return fmt.Sprintf(" ORDER BY %s %s %s", src.Column, dir, nulls), nil
	case SourceJSONBPath:
		castType := sqlCastType(src.ValueType)
		return fmt.Sprintf(" ORDER BY (%s)::%s %s %s", src.SQLRef(), castType, dir, nulls), nil
	default:
		return "", fmt.Errorf("search: field %q has unsortable source kind %q", req.Sort.Field, src.Kind)
	}
}

// BuildCountQuery builds a COUNT(*) query with the same WHERE clauses as BuildQuery
// but without LIMIT / OFFSET. Used to compute the total result count.
func BuildCountQuery(reg *Registry, req SearchRequest) (sql string, args []any, err error) {
	clauses, args, err := buildWhere(reg, req.Filters)
	if err != nil {
		return "", nil, err
	}

	q := "SELECT COUNT(*) FROM search_base.dataset_merged"
	if len(clauses) > 0 {
		q += " WHERE " + strings.Join(clauses, " AND ")
	}

	return q, args, nil
}


