package search

import (
	"encoding/json"
	"fmt"
)

// ValidationError describes a single validation failure.
type ValidationError struct {
	Field   string `json:"field"`
	Message string `json:"message"`
}

// Unexported interfaces let the validator access concrete-type metadata without
// widening the public Field interface.
type hasEnumOptions interface{ enumOptions() []EnumOption }
type hasHardBounds interface{ hardBounds() (min, max *float64) }
type hasMaxRadius interface{ maxRadiusKm() float64 }

// ValidateRequest validates a SearchRequest against the registry.
// All errors are collected (no short-circuit) and returned as a slice.
// A nil/empty slice means the request is valid.
//
// The authenticated flag controls access to RESTRICTED fields: when false,
// any filter on a RESTRICTED-searchability field produces a validation error.
func ValidateRequest(reg *Registry, req SearchRequest, authenticated bool) []ValidationError {
	var errs []ValidationError

	for _, fi := range req.Filters {
		field, ok := reg.Lookup(fi.Field)
		if !ok {
			errs = append(errs, ValidationError{Field: fi.Field, Message: "unknown field"})
			continue
		}

		if !IsFieldSearchable(field.Descriptor(), authenticated) {
			errs = append(errs, ValidationError{Field: fi.Field, Message: "field requires authentication"})
			continue
		}

		switch field.Kind() {
		case KindFullText:
			var f FullTextFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			if len(f.Query) > 512 {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: "value exceeds maximum length of 512 characters"})
			}

		case KindSubstring:
			var f SubstringFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			if len(f.Value) > 512 {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: "value exceeds maximum length of 512 characters"})
			}

		case KindExactString:
			var f ExactStringFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			if len(f.Value) > 512 {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: "value exceeds maximum length of 512 characters"})
			}

		case KindExactNumeric:
			var f ExactNumericFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
			}

		case KindNumericRange:
			var f NumericRangeFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			if f.Min == nil && f.Max == nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: "at least one of min or max is required"})
				break
			}
			if hb, ok := field.(hasHardBounds); ok {
				hardMin, hardMax := hb.hardBounds()
				if f.Min != nil && hardMin != nil && *f.Min < *hardMin {
					errs = append(errs, ValidationError{Field: fi.Field,
						Message: "value out of allowed range"})
				}
				if f.Max != nil && hardMax != nil && *f.Max > *hardMax {
					errs = append(errs, ValidationError{Field: fi.Field,
						Message: "value out of allowed range"})
				}
			}

		case KindSingleEnum:
			var f SingleEnumFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			if eo, ok := field.(hasEnumOptions); ok {
				opts := eo.enumOptions()
				if opts != nil && !containsOption(opts, f.Value) {
					errs = append(errs, ValidationError{Field: fi.Field,
						Message: fmt.Sprintf("value %q not in allowed options", f.Value)})
				}
			}

		case KindMultiEnum:
			var f MultiEnumFilter
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			if len(f.Values) == 0 {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: "at least one value required"})
				break
			}
			if eo, ok := field.(hasEnumOptions); ok {
				opts := eo.enumOptions()
				if opts != nil {
					for _, v := range f.Values {
						if !containsOption(opts, v) {
							errs = append(errs, ValidationError{Field: fi.Field,
								Message: fmt.Sprintf("value %q not in allowed options", v)})
						}
					}
				}
			}

		case KindGeo:
			var f GeoFilterInput
			if err := json.Unmarshal(fi.Value, &f); err != nil {
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("invalid filter JSON for kind %s", field.Kind())})
				continue
			}
			switch f.Kind {
			case GeoFilterKindRadius:
				if f.Radius == nil {
					errs = append(errs, ValidationError{Field: fi.Field,
						Message: "radius filter requires radius object"})
				} else {
					if f.Radius.RadiusKm <= 0 {
						errs = append(errs, ValidationError{Field: fi.Field,
							Message: "radius must be positive"})
					}
					if mr, ok := field.(hasMaxRadius); ok {
						if f.Radius.RadiusKm > mr.maxRadiusKm() {
							errs = append(errs, ValidationError{Field: fi.Field,
								Message: fmt.Sprintf("radius exceeds maximum of %g km", mr.maxRadiusKm())})
						}
					}
				}
			case GeoFilterKindBBox:
				if f.BBox == nil {
					errs = append(errs, ValidationError{Field: fi.Field,
						Message: "bbox filter requires bbox object"})
				}
			default:
				errs = append(errs, ValidationError{Field: fi.Field,
					Message: fmt.Sprintf("unknown geo filter kind: %q", f.Kind)})
			}
		}
	}

	// Pagination checks use sentinel field names.
	if req.Limit > MaxLimit {
		errs = append(errs, ValidationError{Field: "_limit",
			Message: fmt.Sprintf("limit exceeds maximum of %d", MaxLimit)})
	}
	if req.Offset < 0 {
		errs = append(errs, ValidationError{Field: "_offset",
			Message: "offset must be non-negative"})
	}

	// UserLocation validation.
	if loc := req.UserLocation; loc != nil {
		if loc.Latitude < -90 || loc.Latitude > 90 {
			errs = append(errs, ValidationError{Field: "_userLocation",
				Message: "latitude must be between -90 and 90"})
		}
		if loc.Longitude < -180 || loc.Longitude > 180 {
			errs = append(errs, ValidationError{Field: "_userLocation",
				Message: "longitude must be between -180 and 180"})
		}
		if loc.State != "" {
			if len(loc.State) != 2 || loc.State[0] < 'A' || loc.State[0] > 'Z' || loc.State[1] < 'A' || loc.State[1] > 'Z' {
				errs = append(errs, ValidationError{Field: "_userLocation",
					Message: "state must be a 2-letter uppercase code"})
			}
		}
	}

	// Blend validation.
	if req.Blend != nil {
		hasNonZero := false
		for _, bw := range req.Blend.Weights {
			if _, ok := rankingProviderMap[bw.Field]; !ok {
				errs = append(errs, ValidationError{Field: "_blend",
					Message: fmt.Sprintf("unknown blend field %q", bw.Field)})
			}
			if bw.Weight < 0 || bw.Weight > 100 {
				errs = append(errs, ValidationError{Field: "_blend",
					Message: fmt.Sprintf("weight for %q must be 0–100", bw.Field)})
			}
			if bw.Weight > 0 {
				hasNonZero = true
			}
		}
		if !hasNonZero {
			errs = append(errs, ValidationError{Field: "_blend",
				Message: "at least one blend weight must be greater than 0"})
		}
	}

	// Sort validation.
	if req.Sort != nil {
		switch req.Sort.Field {
		case "distance":
			if req.UserLocation == nil {
				errs = append(errs, ValidationError{Field: "_sort",
					Message: "sort by distance requires userLocation"})
			}
		case "name":
			// Always valid.
		default:
			f, ok := reg.Lookup(req.Sort.Field)
			if !ok {
				errs = append(errs, ValidationError{Field: "_sort",
					Message: fmt.Sprintf("unknown sort field %q", req.Sort.Field)})
			} else if !f.Descriptor().Sortable {
				errs = append(errs, ValidationError{Field: "_sort",
					Message: fmt.Sprintf("field %q is not sortable", req.Sort.Field)})
			}
		}
	}

	return errs
}

// containsOption returns true when opts contains an entry with Value == v.
func containsOption(opts []EnumOption, v string) bool {
	for _, o := range opts {
		if o.Value == v {
			return true
		}
	}
	return false
}

