// ─────────────────────────────────────────────────────────────────────────────
// ExportableDescriptors
// ─────────────────────────────────────────────────────────────────────────────

func TestExportableDescriptors(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	descs := reg.ExportableDescriptors()

	if len(descs) == 0 {
		t.Fatal("ExportableDescriptors() returned empty slice")
	}

	// Every descriptor must have Exportable=true and OutputDefault non-nil.
	for _, d := range descs {
		if d.Exportable == nil || !*d.Exportable {
			t.Errorf("descriptor %q has Exportable != true", d.Name)
		}
		if d.OutputDefault == nil {
			t.Errorf("descriptor %q has nil OutputDefault", d.Name)
		}
	}

	// Non-exportable fields must be excluded.
	nameSet := make(map[string]bool, len(descs))
	for _, d := range descs {
		nameSet[d.Name] = true
	}
	for _, excluded := range []string{"location", "carnegie_basic", "congressional_district", "fields_of_study"} {
		if nameSet[excluded] {
			t.Errorf("non-exportable field %q should not appear in ExportableDescriptors()", excluded)
		}
	}

	// Verify ordering: themes should be in AllThemes order.
	themeIndex := make(map[search.Theme]int, len(search.AllThemes))
	for i, th := range search.AllThemes {
		themeIndex[th] = i
	}
	for i := 1; i < len(descs); i++ {
		prevIdx := themeIndex[descs[i-1].Theme]
		currIdx := themeIndex[descs[i].Theme]
		if prevIdx > currIdx {
			t.Errorf("theme ordering violated: %q (%s) before %q (%s)",
				descs[i-1].Name, descs[i-1].Theme, descs[i].Name, descs[i].Theme)
		}
	}
}

