func TestBuildQuery_OffsetClamping(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("offset plus limit exceeds max", func(t *testing.T) {
		req := search.SearchRequest{Limit: 20, Offset: 90}
		_, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		limit := args[len(args)-2].(int)
		offset := args[len(args)-1].(int)
		if limit+offset > 100 {
			t.Errorf("limit(%d) + offset(%d) = %d > 100", limit, offset, limit+offset)
		}
	})

	t.Run("negative offset becomes zero", func(t *testing.T) {
		req := search.SearchRequest{Limit: 20, Offset: -5}
		_, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		offset := args[len(args)-1].(int)
		if offset < 0 {
			t.Errorf("expected non-negative offset, got %d", offset)
		}
	})

	t.Run("large limit and offset both capped", func(t *testing.T) {
		req := search.SearchRequest{Limit: 200, Offset: 50}
		_, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		limit := args[len(args)-2].(int)
		offset := args[len(args)-1].(int)
		if limit > 100 {
			t.Errorf("limit %d exceeds MaxLimit", limit)
		}
		if limit+offset > 100 {
			t.Errorf("limit(%d) + offset(%d) = %d > 100", limit, offset, limit+offset)
		}
	})
}

