	t.Run("sortable field is valid", func(t *testing.T) {
		req := search.SearchRequest{
			Sort: &search.SortInput{Field: "enrollment"},
		}
		errs := search.ValidateRequest(reg, req, true)
		if len(errs) != 0 {
			t.Fatalf("expected no errors, got: %v", errs)
		}
	})

	t.Run("non-sortable field produces error", func(t *testing.T) {
		req := search.SearchRequest{
			Sort: &search.SortInput{Field: "institution_type"},
		}
		errs := search.ValidateRequest(reg, req, true)
		if len(errs) != 1 {
			t.Fatalf("expected 1 error, got %d: %v", len(errs), errs)
		}
		if !strings.Contains(errs[0].Message, "not sortable") {
			t.Errorf("unexpected message: %q", errs[0].Message)
		}
	})

