// TestAllFields_VisibilitySearchabilityRequired verifies that every registered
// field has non-empty Visibility and Searchability values. This enforces that
// both flags are treated as required — no field may rely on a zero value.
func TestAllFields_VisibilitySearchabilityRequired(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	for _, d := range reg.Descriptors() {
		if d.Visibility == "" {
			t.Errorf("field %q: Visibility is empty (must be set explicitly)", d.Name)
		}
		if d.Searchability == "" {
			t.Errorf("field %q: Searchability is empty (must be set explicitly)", d.Name)
		}
	}
}

// TestAllFields_ExportableRequired verifies that every registered field has its
// Exportable flag set explicitly (non-nil). Because exportable is stored as
// *bool, a nil value means the field author forgot to set it.
func TestAllFields_ExportableRequired(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	for _, d := range reg.Descriptors() {
		if d.Exportable == nil {
			t.Errorf("field %q: Exportable is nil (must be set explicitly)", d.Name)
		}
	}
}

// TestOutputDescriptors verifies that OutputDescriptors returns only fields with
// a non-nil OutputDefault, that every returned field has a name and label, and
// that the count is a strict subset of all descriptors.
func TestOutputDescriptors(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	all := reg.Descriptors()
	out := reg.OutputDescriptors()

	if len(out) == 0 {
		t.Fatal("OutputDescriptors() returned empty slice — at least some fields must be output fields")
	}
	if len(out) >= len(all) {
		t.Errorf("OutputDescriptors() count %d >= all descriptors %d; some fields should be input-only", len(out), len(all))
	}

	for _, d := range out {
		if d.Name == "" {
			t.Errorf("output descriptor has empty Name: %+v", d)
		}
		if d.Label == "" {
			t.Errorf("output descriptor %q has empty Label", d.Name)
		}
		// OutputDefault must be non-nil (that's the filter criterion).
		if d.OutputDefault == nil {
			t.Errorf("output descriptor %q has nil OutputDefault — OutputDescriptors() filter is broken", d.Name)
		}
	}
}

// TestOutputDescriptors_KnownValues spot-checks the outputDefault and sortable
// flags for a representative set of fields.
func TestOutputDescriptors_KnownValues(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	cases := []struct {
		name            string
		wantOutput      bool // true = is an output field (OutputDefault != nil)
		wantDefault     bool // expected *OutputDefault when wantOutput=true
		wantSortable    bool
	}{
		// Default-visible output fields
		{"name", true, true, true},
		{"city", true, true, true},
		{"state", true, true, true},
		{"enrollment", true, true, true},
		{"institution_type", true, true, false},
		// Available-but-not-default output fields
		{"admission_rate", true, false, true},
		{"tuition_in_state", true, false, true},
		{"rank_us_news_national", true, false, true},
		{"ncaa_conference", true, false, false},
		// Input-only fields — not output fields
		{"location", false, false, false},
		{"carnegie_basic", false, false, false},
		{"congressional_district", false, false, false},
		{"fields_of_study", false, false, false},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			f, ok := reg.Lookup(tc.name)
			if !ok {
				t.Fatalf("field %q not found in registry", tc.name)
			}
			d := f.Descriptor()

			isOutput := d.OutputDefault != nil
			if isOutput != tc.wantOutput {
				t.Errorf("field %q: isOutputField = %v, want %v", tc.name, isOutput, tc.wantOutput)
			}
			if tc.wantOutput && isOutput {
				if *d.OutputDefault != tc.wantDefault {
					t.Errorf("field %q: OutputDefault = %v, want %v", tc.name, *d.OutputDefault, tc.wantDefault)
				}
			}
			if d.Sortable != tc.wantSortable {
				t.Errorf("field %q: Sortable = %v, want %v", tc.name, d.Sortable, tc.wantSortable)
			}
		})
	}
}

// TestField_ExportableKnownValues spot-checks that well-known fields carry the
// expected exportable value, guarding against accidental edits to the registry.
func TestField_ExportableKnownValues(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	cases := []struct {
		name     string
		wantExportable bool
	}{
		// Public institution name — must appear in exports.
		{"name", true},
		// Tuition — key data point for exports.
		{"tuition_in_state", true},
		// Raw coordinates — not a useful CSV column; exportable=false prevents
		// bulk lat/lng scraping.
		{"location", false},
		// Hidden internal classification code — excluded from exports.
		{"carnegie_basic", false},
		// Hidden granular identifier — excluded from exports.
		{"congressional_district", false},
		// Open-ended JSONB blob — not representable as a flat CSV column.
		{"fields_of_study", false},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			f, ok := reg.Lookup(tc.name)
			if !ok {
				t.Fatalf("field %q not found in registry", tc.name)
			}
			d := f.Descriptor()
			if d.Exportable == nil {
				t.Fatalf("field %q: Exportable is nil", tc.name)
			}
			if *d.Exportable != tc.wantExportable {
				t.Errorf("field %q: Exportable = %v, want %v", tc.name, *d.Exportable, tc.wantExportable)
			}
		})
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// BuildExportQuery
// ─────────────────────────────────────────────────────────────────────────────

func TestBuildExportQuery(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("caps limit to maxRows", func(t *testing.T) {
		req := search.SearchRequest{Limit: 1000}
		sql, args, err := search.BuildExportQuery(reg, req, 500)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "LIMIT") {
			t.Errorf("expected LIMIT in query: %s", sql)
		}
		// Last arg is the limit, should be capped to maxRows (500).
		limit := args[len(args)-1]
		if limit != 500 {
			t.Errorf("expected limit capped to 500, got %v", limit)
		}
	})

	t.Run("uses default limit when zero", func(t *testing.T) {
		req := search.SearchRequest{Limit: 0}
		_, args, err := search.BuildExportQuery(reg, req, 500)
		if err != nil {
			t.Fatal(err)
		}
		limit := args[len(args)-1]
		if limit != search.DefaultLimit {
			t.Errorf("expected default limit %d, got %v", search.DefaultLimit, limit)
		}
	})

	t.Run("positive limit within maxRows is preserved", func(t *testing.T) {
		req := search.SearchRequest{Limit: 50}
		_, args, err := search.BuildExportQuery(reg, req, 500)
		if err != nil {
			t.Fatal(err)
		}
		limit := args[len(args)-1]
		if limit != 50 {
			t.Errorf("expected limit 50, got %v", limit)
		}
	})
}

func TestBuildExportQuery_NoOffset(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	req := search.SearchRequest{Limit: 100, Offset: 50}
	sql, _, err := search.BuildExportQuery(reg, req, 500)
	if err != nil {
		t.Fatal(err)
	}
	if strings.Contains(sql, "OFFSET") {
		t.Errorf("export query should not contain OFFSET: %s", sql)
	}
}

func TestBuildExportQuery_UnknownField(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	req := search.SearchRequest{
		Filters: []search.FilterInput{
			{Field: "nonexistent", Value: mustJSON(map[string]any{"value": "x"})},
		},
	}
	_, _, err := search.BuildExportQuery(reg, req, 500)
	if err == nil {
		t.Fatal("expected error for unknown field")
	}
}

// ─────────────────────────────────────────────────────────────────────────────
// ExportableDescriptors
// ─────────────────────────────────────────────────────────────────────────────

func TestExportableDescriptors(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	descs := reg.ExportableDescriptors()

	if len(descs) == 0 {
		t.Fatal("ExportableDescriptors() returned empty slice")
	}

	// Every descriptor must have Exportable=true and OutputDefault non-nil.
	for _, d := range descs {
		if d.Exportable == nil || !*d.Exportable {
			t.Errorf("descriptor %q has Exportable != true", d.Name)
		}
		if d.OutputDefault == nil {
			t.Errorf("descriptor %q has nil OutputDefault", d.Name)
		}
	}

	// Non-exportable fields must be excluded.
	nameSet := make(map[string]bool, len(descs))
	for _, d := range descs {
		nameSet[d.Name] = true
	}
	for _, excluded := range []string{"location", "carnegie_basic", "congressional_district", "fields_of_study"} {
		if nameSet[excluded] {
			t.Errorf("non-exportable field %q should not appear in ExportableDescriptors()", excluded)
		}
	}

	// Verify ordering: themes should be in AllThemes order.
	themeIndex := make(map[search.Theme]int, len(search.AllThemes))
	for i, th := range search.AllThemes {
		themeIndex[th] = i
	}
	for i := 1; i < len(descs); i++ {
		prevIdx := themeIndex[descs[i-1].Theme]
		currIdx := themeIndex[descs[i].Theme]
		if prevIdx > currIdx {
			t.Errorf("theme ordering violated: %q (%s) before %q (%s)",
				descs[i-1].Name, descs[i-1].Theme, descs[i].Name, descs[i].Theme)
		}
	}
}

