import { useMemo } from 'react'
import { ActionIcon, Group, Select } from '@mantine/core'
import { ArrowDownAZ, ArrowUpAZ } from 'lucide-react'
import type { SortState } from './ResultsTable'

interface SortOption {
  value: string
  label: string
  defaultDirection: 'ASC' | 'DESC'
}

const BASE_OPTIONS: SortOption[] = [
  { value: 'name', label: 'Alphabetical', defaultDirection: 'ASC' },
  { value: 'enrollment', label: 'Total Enrollment', defaultDirection: 'DESC' },
  { value: 'admission_rate', label: 'Acceptance Rate', defaultDirection: 'ASC' },
  { value: 'avg_net_price', label: 'Total Price', defaultDirection: 'ASC' },
]

const DISTANCE_OPTION: SortOption = {
  value: 'distance',
  label: 'Distance',
  defaultDirection: 'ASC',
}

const BLEND_OPTION: SortOption = {
  value: 'blend_score',
  label: 'Blend Score',
  defaultDirection: 'ASC',
}

export interface SortControlProps {
  sort: SortState | undefined
  onSortChange: (field: string, direction: 'ASC' | 'DESC') => void
  onSortClear: () => void
  hasLocation: boolean
  hasBlend: boolean
}

export function SortControl({
  sort,
  onSortChange,
  onSortClear,
  hasLocation,
  hasBlend,
}: SortControlProps) {
  const options = useMemo(() => {
    const opts: SortOption[] = [...BASE_OPTIONS]
    if (hasLocation) opts.splice(1, 0, DISTANCE_OPTION)
    if (hasBlend) opts.push(BLEND_OPTION)
    return opts
  }, [hasLocation, hasBlend])

  const selectData = useMemo(
    () => options.map((o) => ({ value: o.value, label: o.label })),
    [options],
  )

  const handleFieldChange = (value: string | null) => {
    if (!value) {
      onSortClear()
      return
    }
    const opt = options.find((o) => o.value === value)
    if (opt) {
      onSortChange(value, opt.defaultDirection)
    }
  }

  const handleToggleDirection = () => {
    if (!sort) return
    onSortChange(sort.field, sort.direction === 'ASC' ? 'DESC' : 'ASC')
  }

  return (
    <Group gap={4} wrap="nowrap">
      <Select
        size="xs"
        placeholder="Sort by..."
        data={selectData}
        value={sort?.field ?? null}
        onChange={handleFieldChange}
        clearable
        comboboxProps={{ withinPortal: true }}
        style={{ width: 170 }}
        aria-label="Sort field"
      />
      {sort && (
        <ActionIcon
          variant="subtle"
          size="sm"
          onClick={handleToggleDirection}
          aria-label={sort.direction === 'ASC' ? 'Sort ascending' : 'Sort descending'}
        >
          {sort.direction === 'ASC' ? <ArrowUpAZ size={16} /> : <ArrowDownAZ size={16} />}
        </ActionIcon>
      )}
    </Group>
  )
}

