import { describe, it, expect, vi } from 'vitest'
import { screen, fireEvent } from '@testing-library/react'
import { renderWithMantine } from '@/test/render'
import { SortControl, type SortControlProps } from './SortControl'

function renderSortControl(overrides: Partial<SortControlProps> = {}) {
  const props: SortControlProps = {
    sort: undefined,
    onSortChange: vi.fn(),
    onSortClear: vi.fn(),
    hasLocation: false,
    hasBlend: false,
    ...overrides,
  }
  const result = renderWithMantine(<SortControl {...props} />)
  return { ...result, props }
}

describe('SortControl', () => {
  it('renders the sort dropdown', () => {
    renderSortControl()
    expect(screen.getByRole('textbox', { name: /sort field/i })).toBeInTheDocument()
  })

  it('does not show direction toggle when no sort is active', () => {
    renderSortControl()
    expect(screen.queryByRole('button', { name: /sort ascending/i })).not.toBeInTheDocument()
    expect(screen.queryByRole('button', { name: /sort descending/i })).not.toBeInTheDocument()
  })

  it('shows direction toggle when sort is active', () => {
    renderSortControl({ sort: { field: 'name', direction: 'ASC' } })
    expect(screen.getByRole('button', { name: /sort ascending/i })).toBeInTheDocument()
  })

  it('calls onSortChange with default direction when field selected', async () => {
    const onSortChange = vi.fn()
    renderSortControl({ onSortChange })

    // Open dropdown and select "Total Enrollment"
    const input = screen.getByRole('textbox', { name: /sort field/i })
    fireEvent.click(input)

    const option = await screen.findByRole('option', { name: /total enrollment/i })
    fireEvent.click(option)

    expect(onSortChange).toHaveBeenCalledWith('enrollment', 'DESC')
  })

  it('calls onSortChange toggling direction on toggle click', () => {
    const onSortChange = vi.fn()
    renderSortControl({
      sort: { field: 'name', direction: 'ASC' },
      onSortChange,
    })

    fireEvent.click(screen.getByRole('button', { name: /sort ascending/i }))
    expect(onSortChange).toHaveBeenCalledWith('name', 'DESC')
  })

  it('does not show distance option when hasLocation is false', () => {
    renderSortControl({ hasLocation: false })
    const input = screen.getByRole('textbox', { name: /sort field/i })
    fireEvent.click(input)
    expect(screen.queryByRole('option', { name: /distance/i })).not.toBeInTheDocument()
  })

  it('shows distance option when hasLocation is true', () => {
    renderSortControl({ hasLocation: true })
    const input = screen.getByRole('textbox', { name: /sort field/i })
    fireEvent.click(input)
    expect(screen.getByRole('option', { name: /distance/i })).toBeInTheDocument()
  })

  it('does not show blend score option when hasBlend is false', () => {
    renderSortControl({ hasBlend: false })
    const input = screen.getByRole('textbox', { name: /sort field/i })
    fireEvent.click(input)
    expect(screen.queryByRole('option', { name: /blend score/i })).not.toBeInTheDocument()
  })

  it('shows blend score option when hasBlend is true', () => {
    renderSortControl({ hasBlend: true })
    const input = screen.getByRole('textbox', { name: /sort field/i })
    fireEvent.click(input)
    expect(screen.getByRole('option', { name: /blend score/i })).toBeInTheDocument()
  })
})

